insert into public.planejamento (
  ano, mes, projeto_id, talhao, atividade_id, equipe_id, quantidade_prevista, data_inicio, data_limite, status, observacoes
)
select
  s.ano, s.mes, p.id, s.talhao, a.id, e.id, s.quantidade_prevista, s.data_inicio, s.data_limite, 'planejado'::planning_status, s.observacoes
from src s
join lateral (select id from public.projetos where nome = s.projeto_nome order by created_at desc limit 1) p on true
join lateral (select id from public.atividades where nome = s.atividade_nome order by created_at desc limit 1) a on true
left join lateral (select id from public.equipes where nome = s.equipe_nome order by created_at desc limit 1) e on true;;

select
  (select count(*) from public.planejamento where ano = 2026 and mes = 5) as itens_planejamento_maio_2026,
  (select count(distinct projeto_id) from public.planejamento where ano = 2026 and mes = 5) as projetos_no_planejamento,
  (select count(distinct atividade_id) from public.planejamento where ano = 2026 and mes = 5) as atividades_no_planejamento,
  'ok' as status;
